// Navbar.js — saf React + CSS, temasız modern navbar
import React, { useEffect, useMemo, useState } from "react";
import "./Navbar.css";

// Kullanıcı adını localStorage'dan okur ({"kullanici": "Ad Soyad"})
function readUserName() {
    try {
        const raw = localStorage.getItem("kullanici");
        if (!raw) return "";
        const parsed = JSON.parse(raw);
        return parsed?.kullanici || "";
    } catch {
        return "";
    }
}

// Basit inline SVG ikonlar (kütüphanesiz)
const Icon = {
    Menu: (props) => (
        <svg viewBox="0 0 24 24" width="18" height="18" aria-hidden {...props}>
            <path fill="currentColor" d="M3 6h18v2H3V6Zm0 5h18v2H3v-2Zm0 5h18v2H3v-2Z" />
        </svg>
    ),
    Search: (props) => (
        <svg viewBox="0 0 24 24" width="16" height="16" aria-hidden {...props}>
            <path fill="currentColor" d="M21 21 16.65 16.65M10.5 18a7.5 7.5 0 1 1 0-15 7.5 7.5 0 0 1 0 15Z" />
        </svg>
    ),
    Bell: (props) => (
        <svg viewBox="0 0 24 24" width="18" height="18" aria-hidden {...props}>
            <path fill="currentColor" d="M12 22a2.5 2.5 0 0 0 2.45-2H9.55A2.5 2.5 0 0 0 12 22Zm7-6V11a7 7 0 1 0-14 0v5l-2 2v1h18v-1l-2-2Z" />
        </svg>
    ),
    Logout: (props) => (
        <svg viewBox="0 0 24 24" width="16" height="16" aria-hidden {...props}>
            <path fill="currentColor" d="M10 17a1 1 0 0 1 1 1v2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h5v2a1 1 0 0 1-2 0V5H6v14h3v-1a1 1 0 0 1 1-1Zm9-5-3-3v2h-6a1 1 0 1 0 0 2h6v2l3-3Z" />
        </svg>
    ),
    Chevron: (props) => (
        <svg viewBox="0 0 24 24" width="16" height="16" aria-hidden {...props}>
            <path fill="currentColor" d="M6 9l6 6 6-6" />
        </svg>
    ),
};

export default function Navbar() {
    const [kullaniciIsmi, setKullaniciIsmi] = useState("");
    const [mobileOpen, setMobileOpen] = useState(false);
    const [profileOpen, setProfileOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);

    useEffect(() => setKullaniciIsmi(readUserName()), []);

    // Scroll olunca gölge/arka plan yoğunluğunu arttır
    useEffect(() => {
        const onScroll = () => setScrolled(window.scrollY > 8);
        onScroll();
        window.addEventListener("scroll", onScroll, { passive: true });
        return () => window.removeEventListener("scroll", onScroll);
    }, []);

    // Ekran genişleyince mobil çekmeceyi kapat
    useEffect(() => {
        const onResize = () => {
            if (window.innerWidth >= 768) setMobileOpen(false);
        };
        window.addEventListener("resize", onResize);
        return () => window.removeEventListener("resize", onResize);
    }, []);

    const initials = useMemo(() => {
        if (!kullaniciIsmi) return "M"; // Misafir
        return kullaniciIsmi
            .split(/\s+/)
            .map((p) => p[0])
            .join("")
            .slice(0, 2)
            .toUpperCase();
    }, [kullaniciIsmi]);

    const handleLogout = () => {
        try { localStorage.removeItem("kullanici"); } catch { }
        window.location.reload();
    };

    return (
        <header className={`nv-wrapper${scrolled ? " nv-wrapper--scrolled" : ""}`} role="banner">
            <nav className="nv" aria-label="Üst menü">
                {/* Sol: Menütuşu + Marka */}
                <div className="nv-left">
                    <button
                        className="nv-iconbtn md-hidden"
                        aria-label="Menüyü aç"
                        onClick={() => setMobileOpen(true)}
                        type="button"
                    >
                        <Icon.Menu />
                    </button>
                    <a className="nv-brand" href="#/">
                        <span className="nv-logo" aria-hidden />
                        <span className="nv-brand-text">Uygulama</span>
                    </a>
                </div>

                {/* Orta: Linkler + Arama (masaüstü) */}
                <div className="nv-center">
                    <a className="nv-link" href="#/">Ana Sayfa</a>
                    <a className="nv-link" href="#/ozellikler">Özellikler</a>
                    <a className="nv-link" href="#/fiyat">Fiyatlandırma</a>

                    <div className="nv-search">
                        <Icon.Search />
                        <input
                            type="search"
                            placeholder="Ara…"
                            aria-label="Sitede ara"
                            onFocus={() => setProfileOpen(false)}
                        />
                    </div>
                </div>

                {/* Sağ: Bildirim + Profil + Çıkış */}
                <div className="nv-right">
                    <button className="nv-iconbtn nv-icondot" aria-label="Bildirimler" type="button" title="Bildirimler">
                        <Icon.Bell />
                        <span className="nv-dot" aria-hidden />
                    </button>

                    <div className="nv-profile" data-open={profileOpen ? "true" : "false"}>
                        <button
                            className="nv-profile-btn"
                            onClick={() => setProfileOpen((v) => !v)}
                            aria-haspopup="menu"
                            aria-expanded={profileOpen ? "true" : "false"}
                            type="button"
                            title={kullaniciIsmi || "Misafir"}
                        >
                            <span className="nv-avatar">{initials}</span>
                            <span className="nv-username">{kullaniciIsmi || "Misafir"}</span>
                            <Icon.Chevron />
                        </button>

                        <div className="nv-profile-menu" role="menu" aria-label="Profil menüsü">
                            <a className="nv-profile-item" role="menuitem" href="#/profil">Profil</a>
                            <a className="nv-profile-item" role="menuitem" href="#/ayarlar">Ayarlar</a>
                            <button className="nv-profile-item danger" role="menuitem" onClick={handleLogout} type="button">
                                <Icon.Logout /> Çıkış
                            </button>
                        </div>
                    </div>
                </div>
            </nav>

            {/* Mobil çekmece */}
            <div
                className="nv-sheet"
                data-open={mobileOpen ? "true" : "false"}
                onClick={() => setMobileOpen(false)}
                aria-hidden={mobileOpen ? "false" : "true"}
            >
                <div className="nv-drawer" onClick={(e) => e.stopPropagation()}>
                    <div className="nv-drawer-header">
                        <a className="nv-brand" href="#/">
                            <span className="nv-logo" aria-hidden />
                            <span className="nv-brand-text">Uygulama</span>
                        </a>
